    def show_context_menu(self, position):
        context_menu = QMenu()

        selected_text = self.messageBrowser.page().selectedText()

        if selected_text:

            if self.is_url(selected_text):
                print("is link")
                open_link_action = QAction("打开链接", self)
                open_link_action.triggered.connect(lambda: self.open_link(selected_text))
                context_menu.addAction(open_link_action)

            explain_action = QAction("解释选中内容", self)
            explain_action.triggered.connect(lambda: self.explain_text(selected_text))
            context_menu.addAction(explain_action)

            copy_action = QAction("拷贝(Ctrl+C)", self)
            copy_action.triggered.connect(self.copy_text)
            context_menu.addAction(copy_action)



            print("selected_text:", selected_text)

        search_action = QAction("搜索(Ctrl+F1)", self)
        search_action.triggered.connect(self.toggle_search_box)
        context_menu.addAction(search_action)

        # 将搜索选项移到“拷贝”和“打开链接”下面
        actions = context_menu.actions()
        if len(actions) > 1:
            actions[0], actions[1] = actions[1], actions[0]

        context_menu.exec_(self.messageBrowser.mapToGlobal(position))

