    def open_file(self, file_path):
        if sys.platform == "win32":
            os.startfile(file_path)
        elif sys.platform == "darwin":
            subprocess.call(("open", file_path))
        else:
            subprocess.call(("xdg-open", file_path))

    def add_attachment_area(self, attachments):
        self.remaining_attachments += len(attachments)
        self.current_attachment_list += attachments  # 更新附件列表

        if not hasattr(self, 'attachment_frame'):
            self.attachment_frame = QFrame()
            self.attachment_frame.setObjectName("attachmentFrame")
            self.attachment_layout = QHBoxLayout(self.attachment_frame)
            self.attachment_layout.setObjectName("attachmentLayout")
            self.attachment_layout.setContentsMargins(0, 0, 0, 0)
            self.attachment_layout.setAlignment(Qt.AlignCenter)
            self.attachment_frame.setMaximumHeight(40)
            self.vboxlayout.insertWidget(3, self.attachment_frame)

        self.attachment_frame.setVisible(True)

        for attachment in attachments:
            file_content_tuple = get_file_content_tuple(attachment)
            print(file_content_tuple)
            self.attachment_content_list.append(file_content_tuple)  # 将附件内容添加到列表
            # self.current_attachment_content += "\n" + file_content_tuple  # 更新合并的内容
            file_name = os.path.basename(attachment)
            attachment_label = QLabel(f'<a href="#">{file_name}</a>')
            attachment_label.setOpenExternalLinks(False)
            attachment_label.linkActivated.connect(lambda _, file=attachment: self.open_file(file))

            delete_label = QLabel('<a href="#" style="color:red">删除</a>')
            delete_label.setOpenExternalLinks(False)
            delete_label.linkActivated.connect(lambda _, lbl=attachment_label, del_lbl=delete_label, file=attachment: self.remove_attachment(lbl, del_lbl, file))

            self.attachment_layout.addWidget(attachment_label)
            self.attachment_layout.addWidget(delete_label)

            # 存储附件标签以便后续删除
            self.attachment_labels.append((attachment_label, delete_label))

            self.attachment_layout.setAlignment(QtCore.Qt.AlignCenter)

    def remove_attachment(self, attachment_label, delete_label, attachment):
        # 从附件列表中移除
        index = self.current_attachment_list.index(attachment)
        if index >= 0:
            self.current_attachment_list.pop(index)  # 从当前附件列表中删除
            self.attachment_content_list.pop(index)  # 从附件内容列表中删除

        # 更新 current_attachment_content
        # self.current_attachment_content = "\n".join(self.attachment_content_list)  # 重新组合内容

        # 隐藏标签
        attachment_label.setVisible(False)
        delete_label.setVisible(False)
        self.remaining_attachments -= 1
        self.check_attachments_visibility()

    def remove_all_attachments(self):
        """删除所有附件及其内容"""
        for attachment_label, delete_label in self.attachment_labels:
            attachment_label.setVisible(False)  # 隐藏附件标签
            delete_label.setVisible(False)  # 隐藏删除标签

        self.current_attachment_list.clear()  # 清空当前附件列表
        self.attachment_content_list.clear()  # 清空附件内容列表
        # self.current_attachment_content = ""  # 重置合并后的附件内容
        self.remaining_attachments = 0  # 更新剩余附件计数

        # 隐藏附件框
        if hasattr(self, 'attachment_frame'):
            self.attachment_frame.setVisible(False)

        # 清空附件标签列表
        self.attachment_labels.clear()

    def check_attachments_visibility(self):
        if self.remaining_attachments == 0:
            self.attachment_frame.setVisible(False)

    def toggle_page_all_checkboxes_status(self, state):
        """
        根据复选框的状态调用相应的JavaScript函数
        :param state: 当前复选框的状态，0为未选中，2为选中
        """
        if state == 2:  # 复选框被选中
            # 调用 JavaScript 函数将所有复选框设为选中
            self.messageBrowser.page().runJavaScript('setAllCheckboxesChecked(true);')
        else:  # 复选框未选中
            # 调用 JavaScript 函数将所有复选框设为未选中
            if self.conten_menu_closing == True:#点击了内容菜单的关闭按钮
                if self.history_mode_checkbox.isChecked()==False:#如果没有选中指定上下文
                    self.messageBrowser.page().runJavaScript('setAllCheckboxesChecked(false);')

                self.conten_menu_closing = False#处理好复原

            else:#如果不是点击关闭内容菜单按钮
                self.messageBrowser.page().runJavaScript('setAllCheckboxesChecked(false);')



